/**
 * Marcas sin SVG público disponible. Renderizamos un badge tipográfico
 * con un tinte sutil del color de marca para diferenciar. Honesto, consistente
 * y sin problemas de copyright/marca.
 */
interface TextBadge {
  /** Texto corto a mostrar (idealmente 3-5 caracteres). */
  text: string;
  /** Tinte hex sin # (border + text glow muy sutil). */
  accent?: string;
}

const TEXT_BADGES: Record<string, TextBadge> = {
  // Microsoft suite
  microsoftteams: { text: "Teams", accent: "5B5FC7" },
  microsoftexcel: { text: "Excel", accent: "0F7B43" },
  microsoftoutlook: { text: "Outlook", accent: "0078D4" },
  microsoftsharepoint: { text: "Share", accent: "036C70" },
  // ERPs LATAM
  siesa: { text: "Siesa", accent: "F25C29" },
  siigo: { text: "Siigo", accent: "FBB03B" },
  worldoffice: { text: "WO", accent: "1C70E7" },
};

/**
 * Brand logo wrapper. Resolución en este orden:
 *   1. Inline SVG (slugs en `InlineLogos`) — para marcas grandes sin CDN
 *   2. Text badge (slugs en `TEXT_BADGES`) — fallback honesto sin SVG público
 *   3. Simple Icons CDN — el caso común
 */
export function BrandLogo({ slug, name, size = 24, color = "FAFAFA", className }: BrandLogoProps) {
  const Inline = InlineLogos[slug];
  if (Inline) {
    return <Inline size={size} className={cn("block shrink-0", className)} />;
  }

  const badge = TEXT_BADGES[slug];
  if (badge) {
    // El badge escala razonablemente. Para chips de 16-18px de size, usar 9-10px font.
    const fontSize = Math.max(8, Math.floor(size * 0.46));
    return (
      <span
        role="img"
        aria-label={name}
        className={cn(
          "inline-flex items-center justify-center rounded-[4px] border bg-card font-mono uppercase tracking-tight text-foreground/85",
          className,
        )}
        style={{
          height: size,
          minWidth: size,
          paddingInline: Math.max(3, size * 0.18),
          fontSize,
          lineHeight: 1,
          borderColor: badge.accent
            ? `rgba(${Number.parseInt(badge.accent.slice(0, 2), 16)},${Number.parseInt(badge.accent.slice(2, 4), 16)},${Number.parseInt(badge.accent.slice(4, 6), 16)},0.45)`
            : undefined,
        }}
      >
        {badge.text}
      </span>
    );
  }

  return (
    // biome-ignore lint/performance/noImgElement: external SVG, no need for next/image optimization
    <img
      src={`https://cdn.simpleicons.org/${slug}/${color}`}
      alt={name}
      width={size}
      height={size}
      loading="lazy"
      decoding="async"
      className={cn("block shrink-0 select-none", className)}
      style={{ width: size, height: size }}
    />
  );
}
